E.append({"id":"toxin-001","category":"toxicology","title":"犬用驱虫药中毒(苄氯菊酯)—给猫误用狗药","symptom_text":"主人误将犬用体外驱虫药(含苄氯菊酯/permethrin)滴在猫身上。数小时内猫出现：剧烈颤抖/震颤、流口水、抽搐、走路不稳、发烧。苄氯菊酯对猫剧毒——猫肝脏缺乏代谢它的酶。这是最常见的猫中毒原因之一。","image_features":"猫全身颤抖、流口水、可能抽搐","risk_level":"high","possible_causes":["误用含苄氯菊酯的犬用驱虫药","接触刚驱虫的狗"],"home_treatment":"1)立即洗掉猫身上的药(用洗洁精+温水彻底清洗)。2)立即送急诊。不要观望——震颤可迅速进展为癫痫持续状态。","when_to_see_vet":"立即急诊。","typical_cost_range":"2000-8000元(洗消+抗癫痫+支持治疗)","typical_duration":"住院1-5天","evidence":{"source":"Vet Clin North Am Small Anim Pract, 10 Most Common Toxicoses","key_stats":["苄氯菊酯是最常见的猫中毒原因之一","猫肝缺乏葡萄糖醛酸转移酶→无法代谢拟除虫菊酯","尽快洗消+支持治疗→存活率>90%","延误治疗→死亡率显著上升(癫痫持续状态→脑损伤)"],"evidence_level":"A"},"real_case_summary":"猫友：我妈不知道哪里拿的狗驱虫药给猫滴了，半小时后猫开始浑身抖。冲急诊洗了澡+打了镇静剂+住院两天。还好来得快。永远记住：犬用驱虫药绝对不能给猫用！","keywords":["苄氯菊酯","犬药","猫中毒","颤抖","抽搐","驱虫药误用"]})

E.append({"id":"toxin-002","category":"toxicology","title":"退热药中毒(布洛芬)—1片可杀猫","symptom_text":"猫吃了布洛芬/对乙酰氨基酚(扑热息痛)/阿司匹林等人类退热止痛药。猫可在数小时内出现：呕吐(可能带血)、精神萎靡、呼吸急促、牙龈发棕/蓝(高铁血红蛋白血症)、面部水肿。1片200mg布洛芬即可杀死一只猫。对乙酰氨基酚同样致死。","image_features":"牙龈发棕/蓝，面部水肿，呼吸急促","risk_level":"high","possible_causes":["误食人类退热止痛药","主人自行给猫喂人药"],"home_treatment":"立即急诊！不要催吐(可能造成二次伤害)。带上药瓶让医生知道成分和剂量。","when_to_see_vet":"立即急诊。猫对人类NSAID极其敏感—1片就致命。","typical_cost_range":"3000-15000元(急救+解毒剂+输血+ICU)","typical_duration":"住院3-10天","evidence":{"source":"Vet Clin North Am Toxicol / ASPCA Poison Control","key_stats":["布洛芬猫致死剂量~50-100mg/kg(1片200mg可杀4kg猫)","对乙酰氨基酚猫中毒剂量~10mg/kg(远低于人用剂量)","对乙酰氨基酚中毒→高铁血红蛋白血症→若不治疗致死率>90%","N-乙酰半胱氨酸是对乙酰氨基酚的有效解毒剂(需尽早使用)"],"evidence_level":"A"},"real_case_summary":"猫友：猫不知道从哪里翻出一颗布洛芬吃了，半小时后呕吐带血丝。送急诊洗胃+输液+护肾药，住了四天花了6000多，还好救回来了。家里所有人类药都锁起来了——之前觉得猫不会吃。","keywords":["布洛芬","退热药","扑热息痛","中毒","呕吐带血","牙龈变色"]})

# ============ INFECTIOUS ============
E.append({"id":"infect-002","category":"infectious","title":"猫艾滋(FIV)—慢性免疫低下","symptom_text":"猫(通常户外未绝育公猫，打架咬伤传播)可能长期无症状(数年)。后期出现：反复口腔炎/牙龈炎、慢性上呼吸道感染、体重下降、毛发差、反复腹泻、伤口难愈合。不是人类的HIV——不会传染给人。","image_features":"口腔炎、消瘦、毛发粗糙","risk_level":"medium","possible_causes":["猫免疫缺陷病毒(FIV)—咬伤传播(主要)","母婴传播(次要)"],"home_treatment":"1)FIV没有特效药—管理是维持免疫力和预防继发感染。2)室内养(保护猫也保护其他猫)。3)优质营养+减少应激。4)定期半年体检(血常规+生化)。5)发现任何感染早期治疗。6)FIV猫可以和其他猫一起养如果它们不打架。7)抗病毒药(如齐多夫定)效果有限。","when_to_see_vet":"任何感染迹象(口炎/呼吸道/腹泻)都应早期就医。FIV猫对感染耐受差。","typical_cost_range":"初次诊断200-500元(快速检测+确诊)，长期管理视并发症","typical_duration":"终身携带—部分FIV+猫可活到正常寿命","evidence":{"source":"ABCD Guidelines, J Feline Med Surg","key_stats":["FIV全球患病率~1-14%(地区差异大)","户外未绝育公猫感染率最高(咬伤传播)","FIV+猫中位生存时间4-6年(诊断后)，部分可活10+年","不会传染给人—FIV是猫专属病毒"],"evidence_level":"A (国际共识指南)"},"real_case_summary":"猫友：收编的流浪公猫体检发现FIV阳性，当时以为判了死刑。医生说室内养+好好照顾可以活很多年。现在四年了，除了偶尔口腔炎，生活质量很好。FIV不是绝症。","keywords":["FIV","猫艾滋","口腔炎","流浪猫","免疫低下","打架"]})

E.append({"id":"infect-003","category":"infectious","title":"猫白血病(FeLV)—最具破坏力的猫病毒","symptom_text":"猫(尤其幼猫和多猫环境)可能出现：持续体重下降、反复发烧、贫血(牙龈苍白)、淋巴瘤(体表肿块)、慢性感染。部分猫可自行清除病毒(退行性感染)，部分持续携带(进行性感染)。FeLV通过唾液/鼻涕/尿液/粪便/乳汁传播——共用食碗、互相舔毛即可传播。","image_features":"消瘦、贫血、体表可能肿块(淋巴瘤)、口腔炎","risk_level":"high","possible_causes":["猫白血病病毒(FeLV)—密切接触传播"],"home_treatment":"1)FeLV+猫必须室内单独饲养或只与其他FeLV+猫生活。2)优质营养+减少应激。3)至少半年一次体检+血检。4)任何疾病早期干预。5)进行性FeLV猫中位生存时间2-3年(诊断后)。退行性感染(自行清除病毒)可正常生活。6)抗病毒药(AZT/干扰素)效果有限。","when_to_see_vet":"任何生病迹象→立即就医(FeLV猫耐受差)。","typical_cost_range":"快速检测100-300元，确诊+分期500-1500元","typical_duration":"进行性→中位生存2-3年。退行性→正常寿命","evidence":{"source":"ABCD Guidelines, J Vet Intern Med","key_stats":["FeLV全球患病率~2-3%(家猫)，流浪猫>10%","幼猫(<>6月龄)感染后>70%发展为进行性","成年猫感染后>70%可清除病毒(退行性)","FeLV+猫中位生存2-3年(进行性)，部分跨过5年","FeLV是猫肿瘤(淋巴瘤/白血病)的首要病毒原因"],"evidence_level":"A (国际共识指南)"},"real_case_summary":"猫友：领养了两只猫，其中一只体检FeLV+。崩溃之后查了很多资料，决定分开养——FeLV+单猫养在一个房间，另一只打了疫苗。一年多了阳性那只状态很好，定期体检。希望它能多活几年。","keywords":["FeLV","白血病","猫白血病","传染","淋巴瘤","贫血"]})

# ============ ENDOCRINE ============
E.append({"id":"endo-001","category":"endocrine","title":"甲亢—老年猫暴瘦但猛吃","symptom_text":"猫(通常>10岁)食量明显增加但体重持续下降、多饮多尿、活动增多/烦躁、呕吐、毛发蓬乱、可能嚎叫增多。颈部可能摸到肿大的甲状腺(正常摸不到)。甲亢是老年猫最常见的内分泌疾病。","image_features":"猫消瘦但肌肉消耗明显、毛发凌乱、颈部可能触及小肿块","risk_level":"medium","possible_causes":["甲状腺腺瘤/增生(良性为主，恶性肿瘤<2%)"],"home_treatment":"需要就医确诊(血T4)。三种治疗方案可选：1)每日口服药(甲巯咪唑)—最常用、便宜但需终身服药。2)放射性碘131治疗—治愈率>95%，一次性但贵(需专科中心)。3)处方低碘粮(希尔斯y/d)—仅限早期。","when_to_see_vet":">10岁猫体重下降+食量增加→查T4。未治疗的甲亢可导致心脏病(HCM)和高血压。","typical_cost_range":"口服药：每月100-300元。I131治疗：8000-15000元(一次性)","typical_duration":"终身管理。I131可治愈","evidence":{"source":"ISFM Hyperthyroidism Guidelines","key_stats":[">10岁猫甲亢患病率~10-15%",">15岁猫甲亢患病率~20-30%","I131治愈率>95%，是'金标准'","口服甲巯咪唑的副作用率~15-20%(呕吐/厌食/面部瘙痒)"],"evidence_level":"A (国际共识指南)"},"real_case_summary":"猫友：13岁老猫突然暴吃暴瘦，还以为它终于胃口好了。体检T4爆表，确诊甲亢。现在每天喂甲巯咪唑，体重稳定了。医生建议做I131根治，正在攒钱。","keywords":["甲亢","暴瘦","老年猫","T4","暴食","I131"]})

# ============ SKIN (more) ============
E.append({"id":"skin-007","category":"skin","title":"嗜酸性肉芽肿(无痛性溃疡)—上唇红肿","symptom_text":"猫上唇边缘出现红肿、增厚、溃疡（像被蜜蜂蛰了）。可能单侧或双侧。猫不痒不抓。这是嗜酸性肉芽肿复合体的一种表现。可能与过敏(食物/跳蚤/环境)或遗传有关。母猫比公猫多发。","image_features":"上唇边缘红肿增厚，可能有溃疡，外形像'噘嘴'","risk_level":"medium","possible_causes":["嗜酸性肉芽肿复合体","食物/跳蚤/环境过敏","特发性","与细菌感染/牙病相关(少见)"],"home_treatment":"1)排查跳蚤并驱虫。2)食物排除试验(换新蛋白源)。3)部分会自愈。4)如果反复或严重→就医可能需要激素治疗。","when_to_see_vet":">2周无改善/进食困难/范围扩大/出现多处","typical_cost_range":"100-1000元(驱虫+换粮+可能激素药)","typical_duration":"轻的自愈2-4周，反复的可能需要长期管理","evidence":{"source":"Vet Dermatol 综述","key_stats":["嗜酸性肉芽肿复合体是猫第二常见的过敏性皮肤病(仅次于粟粒性皮炎)","~40%与跳蚤过敏有关","食物过敏占~20-30%","激素治疗有效率>80%但可能复发"],"evidence_level":"B"},"real_case_summary":"猫友：猫上嘴唇突然肿了，像香肠嘴。医生说是嗜酸性肉芽肿，可能和跳蚤过敏有关。做了驱虫+短暂用激素，两周好了。","keywords":["嘴唇肿","无痛性溃疡","嗜酸性肉芽肿","香肠嘴","过敏"]})

# ============ UROLOGY ============
E.append({"id":"urinary-004","category":"urinary","title":"膀胱结石—反复尿道感染","symptom_text":"猫反复出现尿频、尿血、排尿疼痛。和尿闭不同的是尿量尚可但尿液带血。B超/X光可发现膀胱内结石。猫最常见的两种结石：磷酸铵镁(鸟粪石)和草酸钙。鸟粪石可通过饮食溶解，草酸钙只能手术。","image_features":"B超/X光可见膀胱内高密度影","risk_level":"medium","possible_causes":["磷酸铵镁结石(鸟粪石)—碱性尿+镁高→饮食可溶解","草酸钙结石—酸性尿+钙高→需手术","尿路感染","饮水不足"],"home_treatment":"需要就医确诊结石类型。鸟粪石：处方粮(酸化尿液+低镁)可2-4周内溶解>90%结石。草酸钙：手术取出+终身处方粮预防复发。所有结石猫：无限饮水+湿粮为主。","when_to_see_vet":"尿血+疼痛→就医。小结石可能进入尿道变成尿闭→急症。","typical_cost_range":"500-5000元(检查+饮食治疗/手术)","typical_duration":"鸟粪石溶解2-4周；草酸钙手术+恢复2-3周","evidence":{"source":"Canadian Veterinary Urolith Centre 50,000+结石分析","key_stats":["鸟粪石占猫膀胱结石~40-50%(过去更常见)","草酸钙占~40-50%(近年增加—与饮食酸化有关)","鸟粪石处方粮溶解率>90%(2-4周)","草酸钙复发率~20-30%(需终身预防)"],"evidence_level":"A (大样本流行病学)"},"real_case_summary":"猫友：猫尿血做B超发现膀胱里两颗小结石。尿检是鸟粪石，开了处方粮吃了一个月，复查结石没了。原来是之前的猫粮镁含量太高。","keywords":["膀胱结石","鸟粪石","草酸钙","尿血","处方粮","B超"]})

# ============ REPRODUCTIVE ============
E.append({"id":"repro-001","category":"reproductive","title":"子宫蓄脓—未绝育母猫的定时炸弹","symptom_text":"未绝育母猫(任何年龄，发情后2-8周高发)出现：阴道流脓性或血性分泌物(开放型)或不流但腹围增大(闭合型更危险)、多饮多尿、发烧、精神萎靡、呕吐、不吃。闭合型子宫蓄脓没有分泌物但子宫内积脓→可破裂→腹膜炎→死亡。","image_features":"阴道脓性分泌物(开放型)，腹部膨大(闭合型)，猫精神萎靡","risk_level":"high","possible_causes":["未绝育母猫—孕酮→子宫内膜囊性增生→继发细菌感染(大肠杆菌最常见）"],"home_treatment":"立即就医。唯一有效治疗是紧急手术摘除子宫卵巢(类似绝育但更复杂、风险更高)。抗生素不能根治—只能拖时间。","when_to_see_vet":"任何疑似子宫蓄脓→立即急诊。闭合型破裂后腹膜炎→死亡率>50%。","typical_cost_range":"3000-10000元(紧急子宫卵巢摘除术+抗生素+输液)","typical_duration":"术后住院3-5天，恢复2周","evidence":{"source":"Theriogenology 研究","key_stats":["未绝育母猫终身子宫蓄脓风险~15-25%(>8岁)","发情后2-8周为高发窗口","紧急手术存活率~90-95%(破裂前)","闭合型破裂后死亡率>50%","绝育后子宫蓄脓风险=0%"],"evidence_level":"A (大量临床研究)"},"real_case_summary":"猫友：猫没绝育因为想让她生一窝。5岁的时候突然精神不好，阴道流脓。确诊子宫蓄脓，紧急手术花了5000多。医生说再拖两天子宫可能就破了。从此所有猫都尽早绝育。","keywords":["子宫蓄脓","母猫","未绝育","阴道流脓","紧急手术","绝育"]})

# ============ TRAUMA ============
E.append({"id":"trauma-001","category":"trauma","title":"高楼坠落综合征—猫从高处掉下来","symptom_text":"猫从2楼以上高度坠落。常见的损伤包括：上腭裂(口腔顶裂开)、气胸(呼吸困难)、骨折(尤其下颌和四肢)、内出血、膀胱破裂。奇怪的是：3-6楼坠落往往比2楼更重(猫没时间翻身)。表面可能没有明显外伤但内部损伤严重。","image_features":"口腔上腭可能裂开，呼吸困难，某个肢体变形","risk_level":"high","possible_causes":["从阳台/窗户/高处跌落"],"home_treatment":"立即急诊！即使猫能站起来走路也要检查——内出血和气胸可能几小时后才显现。搬运时用硬板/航空箱，减少移动。","when_to_see_vet":"所有高楼坠落→立即急诊，无论表面看起来多轻微。","typical_cost_range":"2000-20000元(取决于损伤程度—X光/CT+手术+ICU)","typical_duration":"轻的住院1-3天，重的(多处骨折/内出血)数周","evidence":{"source":"JAVMA 119例高楼坠落回顾性研究","key_stats":["高楼坠落猫总生存率~90-95%(猫有'翻正反射'和低体重/表面积比优势)","3-6楼损伤反比>6楼重(猫达到终端速度后放松→损伤分布更均匀)","最常见损伤：上腭裂(~30-40%)、气胸(~20%)、骨折(~20%)","坠落高度和损伤严重度不呈线性相关"],"evidence_level":"A (经典临床研究)"},"real_case_summary":"猫友：猫从4楼阳台掉下去，以为完蛋了。找到时猫躲在花坛里，带去急诊发现只有上腭裂了，住了两天院观察。医生说猫从高处掉下来存活率很高，但一定要封阳台——下次可能没这么幸运。","keywords":["坠楼","高楼","阳台","上腭裂","气胸","封窗"]})

# ============ GASTRO ============
E.append({"id":"gastro-001","category":"digestive","title":"巨结肠/顽固便秘—需要手术的便秘","symptom_text":"猫长期严重便秘(数天到数周不大便)，腹部可触及硬粪块。反复灌肠无效，拍X光显示结肠极度扩张(正常结肠宽度<1.5倍L5椎体长度，巨结肠>2倍)。常见于长期慢性便秘/骨盆骨折后遗症/特发性巨结肠。最终结肠失去蠕动能力→只能手术切除。","image_features":"X光显示极度扩张的结肠充满粪便","risk_level":"high","possible_causes":["长期慢性便秘→结肠平滑肌不可逆损伤","骨盆骨折后遗症(骨痂压迫结肠)","特发性巨结肠(神经节细胞缺失—Manx猫高发)"],"home_treatment":"轻度可用乳果糖/西沙必利+高纤饮食+增加饮水控制。但一旦结肠扩张>2倍L5椎体→药物无效→需结肠次全切除术。","when_to_see_vet":"便秘>3天+药物无效→就医。反复便秘>6个月→考虑手术评估。","typical_cost_range":"轻的每月50-200元(药物)，手术8000-20000元","typical_duration":"手术+恢复4-6周","evidence":{"source":"J Feline Med Surg / Vet Surg","key_stats":["结肠次全切除术成功率~80-90%(生活质量显著改善)","术后最常见的并发症是短期腹泻(通常数周-数月自行改善)","长期慢性便秘→巨结肠进展率~30-50%","手术猫中位恢复满意排便控制时间~1-3个月"],"evidence_level":"B"},"real_case_summary":"猫友：猫便秘一年多，从乳果糖吃到灌肠都只能管一阵。最后结肠失去功能，做了结肠切除术。术后前两个月拉稀，现在半年后排便正常了。虽然手术贵但猫终于不痛苦了。","keywords":["巨结肠","便秘","不拉","结肠切除","骨盆骨折","灌肠"]})

# ============ BEHAVIOR ============
E.append({"id":"behav-005","category":"behavioral","title":"猫过度理毛(精神性脱毛)—舔秃自己","symptom_text":"猫过度舔舐/拔自己腹侧、大腿内侧的毛发，导致局部秃毛但皮肤光滑无病变。与过敏性皮炎的区别：精神性脱毛的猫常在主人不在时或夜间舔，且有其他应激表现(躲藏/食欲变化)。可能由环境变化/无聊/焦虑触发。暹罗猫等东方品种多发。","image_features":"对称性秃毛，皮肤正常光滑，毛发断裂(舔断)","risk_level":"medium","possible_causes":["精神性/心因性过度理毛(焦虑/无聊/应激)","排除身体原因后诊断(过敏/疼痛/寄生虫→都排除后→考虑精神性)"],"home_treatment":"1)增加每日互动和玩具(环境丰容)。2)费洛蒙扩散器。3)设定固定日常routine减少不确定性。4)益智玩具/藏食减少无聊。5)如果无效→兽医可能开抗焦虑药(氟西汀/氯米帕明)。","when_to_see_vet":"必须首先排除身体原因(食物过敏/寄生虫/疼痛)→然后再考虑精神性。如果舔至皮肤破损/感染→立即就医。","typical_cost_range":"200-800元(排除身体原因)，精神性管理每月50-200元","typical_duration":"环境调整2-4周起效,严重者需长期管理","evidence":{"source":"AAFP/ISFM Behavior Guidelines","key_stats":["精神性过度理毛在暹罗猫/东方品种中发病率是其他品种的3-5倍",">60%对环境丰容+费洛蒙有良好反应(无需药物)","严重者抗焦虑药有效率~70-80%","复发常见(约40-50%)——与主人生活变化相关"],"evidence_level":"B"},"real_case_summary":"猫友：猫把自己肚子舔得光秃秃，去皮肤科花了两千排除了过敏和寄生虫。最后是精神性的——我那段时间经常出差。买了自动逗猫玩具+费洛蒙，两周后好转。猫真的会因为孤独舔毛。","keywords":["精神性脱毛","舔秃","焦虑","无聊","费洛蒙","暹罗猫"]})

# ============ DENTAL ============
E.append({"id":"oral-003","category":"oral","title":"猫慢性龈口炎(FCGS)—让猫痛不欲生的口腔病","symptom_text":"猫整个口腔(不仅牙龈)弥漫性红肿、溃疡、增生，尤以后部(舌腭弓/咽部)为甚。极度口臭、流口水带血丝、吃饭时惨叫跑开、不敢吃干粮、体重下降。常规洗牙/抗生素只能暂时缓解。这是免疫介导性疾病，不是单纯的牙结石问题。","image_features":"全口腔弥漫性红肿溃疡，尤以咽部/舌腭弓为重","risk_level":"high","possible_causes":["免疫介导性—对牙菌斑的过度免疫反应","与杯状病毒(FCV)慢性感染强相关","FIV/FeLV+猫更常见"],"home_treatment":"1)初期可用兽医开口腔喷剂/漱口水缓解。2)但根治方案是全口/近全口拔牙(移除牙菌斑=移除抗原刺激)。3)拔牙后~60-80%猫显著改善，其中~50%完全缓解。4)剩余猫需免疫抑制剂(激素/环孢素)长期管理。","when_to_see_vet":"尽早—拖延导致猫长期忍痛。足量治疗(拔牙)是减少痛苦的最好方式。","typical_cost_range":"3000-12000元(全口拔牙+术前检查+术后管理)","typical_duration":"拔牙后2-4周显著改善，部分猫需终身药物管理","evidence":{"source":"J Vet Dent / J Feline Med Surg","key_stats":["FCGS患病率~0.7-12%(猫群差异大—收容所/流浪猫更高)","杯状病毒(FCV)在FCGS猫中检出率>80%","全口拔牙→~60%完全缓解，~20%显著改善，~20%无改善需药物","拔牙猫生活质量评分>90%——拔牙后猫明显更快乐"],"evidence_level":"A (多项大型病例系列+系统综述)"},"real_case_summary":"猫友：猫流口水带血、吃饭惨叫，确诊口炎。一听说要全口拔牙崩溃了。但看着猫痛得吃不了饭，还是做了。拔牙后两周猫吃饭正常了，体重回升。医生说得对——没牙的猫比有牙但痛的猫幸福一万倍。","keywords":["口炎","全口红肿","流口水带血","全口拔牙","FCGS","吃饭惨叫"]})

# ============ OPHTHALMOLOGY ============
E.append({"id":"eye-005","category":"eye","title":"青光眼—眼压升高可致失明","symptom_text":"猫一只眼突然变大、突出、角膜混浊发白、瞳孔散大固定、眼白充血、猫眯眼/流泪/畏光。急性青光眼发作可以24-48小时内导致不可逆失明。通常继发于葡萄膜炎/晶状体脱位/眼内肿瘤等，原发性青光眼在猫中罕见。","image_features":"眼大突出，角膜混浊，瞳孔散大固定，眼白充血","risk_level":"high","possible_causes":["继发性青光眼(>95%—葡萄膜炎/肿瘤/晶状体脱位)", "原发性青光眼(<5%—暹罗/缅甸猫)"],"home_treatment":"不可居家处理。急性青光眼是眼科急症。","when_to_see_vet":"发现眼大突出+角膜混浊→立即急诊眼科。24-48小时可永久失明。","typical_cost_range":"2000-10000元(急诊降眼压+病因治疗+可能需要手术)","typical_duration":"取决于病因——部分可控制，部分最终需要摘除眼球","evidence":{"source":"Vet Ophthalmol 综述","key_stats":["猫青光眼中>95%为继发性(非原发)","急性青光眼→24-48小时视网膜不可逆损伤","葡萄膜炎是猫继发性青光眼最常见原因","难治性青光眼终末期→眼球摘除(猫适应良好)"],"evidence_level":"B"},"real_case_summary":"猫友：猫一只眼睛突然变大变白，急诊说急性青光眼，眼压爆表。降眼压药+病因治疗后暂时保住了眼球但视力永久损伤。医生说如果早来半天可能保得住视力。","keywords":["青光眼","眼大","角膜混浊","眼压","失明","眼科急诊"]})

# ============ EAR ============
E.append({"id":"ear-002","category":"ear","title":"耳息肉(鼻咽息肉)—呼吸有杂音","symptom_text":"猫(通常<2岁幼猫)出现呼吸杂音(喘鸣)、打鼾、用嘴呼吸、一侧耳朵反复感染、头歪、偶尔打喷嚏带血。息肉从咽鼓管或中耳长出，堵塞鼻咽部。常见于幼猫——可能和慢性上呼吸道感染有关。","image_features":"口腔深处/软腭上方可见粉红色息肉样物(需麻醉下检查)","risk_level":"medium","possible_causes":["鼻咽息肉—起源于咽鼓管或中耳黏膜","可能与慢性上呼吸道感染/杯状病毒有关"],"home_treatment":"需要就医。唯一有效治疗是手术切除(牵引撕脱术或腹侧鼓泡切开术)。","when_to_see_vet":"呼吸杂音+打鼾+反复耳病→需检查咽部(需要镇静/麻醉)。","typical_cost_range":"2000-8000元(手术切除+病理)","typical_duration":"术后恢复1-3周","evidence":{"source":"J Feline Med Surg / Vet Surg","key_stats":["鼻咽息肉在<2岁猫中占>80%","牵引撕脱术复发率~30-50%(根部残留)","腹侧鼓泡切开术复发率<10%(更彻底但创伤更大)","术后预后良好—>90%生活质量改善"],"evidence_level":"B"},"real_case_summary":"猫友：小猫打呼噜比人还响，开始以为可爱。后来发现它用嘴呼吸，去检查发现鼻咽部一个大息肉。手术切掉后呼吸顺畅了。耳息肉容易复发，但至少猫现在不喘了。","keywords":["鼻咽息肉","呼吸杂音","打鼾","幼猫","张嘴呼吸","耳病"]})

E.append({"id":"ear-003","category":"ear","title":"外耳炎—耳朵红肿痒","symptom_text":"猫耳朵外侧红肿、瘙痒、频繁摇头抓耳、耳道内有黄褐色或黑色分泌物、有异味。和耳螨的区别：外耳炎分泌物通常是湿润的(耳螨是干燥咖啡渣状)。可能由细菌/真菌感染、过敏、异物引起。","image_features":"耳廓红肿，耳道湿润分泌物，可能有异味","risk_level":"low","possible_causes":["细菌/真菌(马拉色菌)感染","过敏性外耳炎","异物(草芒等)","耳螨继发细菌感染"],"home_treatment":"1)兽医诊断(耳道镜+耳分泌物染色)确定病因。2)细菌性→抗生素耳药。3)真菌性→抗真菌耳药。4)过敏性→排查过敏原(食物/环境)。5)清理耳道后滴药。","when_to_see_vet":">3天无改善/红肿加重/猫抓破耳廓/怀疑异物","typical_cost_range":"100-500元(检查+耳药)","typical_duration":"用药1-2周恢复","evidence":{"source":"Vet Dermatol","key_stats":["马拉色菌是猫外耳炎最常见真菌原因(~60%)","过敏性外耳炎占猫耳病约20-30%","猫外耳炎复发率>对因治疗(非对症)"],"evidence_level":"B"},"real_case_summary":"猫友：猫耳朵红红的还有味道，以为是耳螨买了耳肤灵没用。去检查是马拉色菌感染，换了一种抗真菌耳药一周就好了。耳朵问题不检查用错药白花钱。","keywords":["外耳炎","耳朵红","分泌物","马拉色菌","异味","抓耳"]})

E.append({"id":"eye-006","category":"eye","title":"葡萄膜炎—眼内发炎可致盲","symptom_text":"猫眼睛出现：瞳孔缩小、虹膜颜色改变、眼白充血、角膜内表面有沉淀物(KP)、前房积脓/积血。猫畏光、流泪、眯眼。葡萄膜炎是眼内炎症的总称，可能是眼部问题也可能是全身疾病的信号(FIP/FIV/FeLV/弓形虫/肿瘤等)。","image_features":"瞳孔缩小、虹膜变色、眼白充血、前房可能混浊","risk_level":"high","possible_causes":["FIP(猫传染性腹膜炎)—最常见严重原因","FIV/FeLV","弓形虫","眼外伤","特发性","肿瘤(尤其老年猫)"],"home_treatment":"需要眼科专科就医。葡萄膜炎必须查全身病因(FIP/FIV/FeLV/弓形虫)—不能只治眼睛。","when_to_see_vet":"发现眼睛颜色/大小/透明度改变→尽早就医。葡萄膜炎可导致青光眼/白内障/视网膜脱离→失明。","typical_cost_range":"1000-5000元(眼科检查+病因筛查+治疗)","typical_duration":"取决于病因——可逆的1-4周，FIP相关的需84天","evidence":{"source":"Vet Ophthalmol","key_stats":["FIP是年轻猫葡萄膜炎最重要原因之一","约20-30%猫葡萄膜炎找不到明确原因(特发性)","未治疗的葡萄膜炎→>60%发展为青光眼/白内障等并发症","猫葡萄膜炎—永远查全身病因！"],"evidence_level":"A (临床共识)"},"real_case_summary":"猫友：猫一只眼睛变色了，眼白红红的。眼科查了发现葡萄膜炎，然后全身筛查竟然是FIP早期。因为眼睛问题发现了FIP，早早开始打441。眼睛好了。","keywords":["葡萄膜炎","眼红","虹膜变色","FIP","瞳孔缩小","眼内炎"]})

